/**
 * ProcessStepsPropertyPanel - Admin Property Panel for Process Steps Timeline
 * Author: generated by Amazon Q
 * Created: 2025-01-01
 * Purpose: Full visual editor for all ProcessStepsSection fields
 */

'use client';

import React, { useState } from 'react';
import { SectionConfig } from '@/lib/page-builder/section-schemas';

interface ProcessStep {
  eyebrow: string;
  badge: string;
  title: string;
  description: string;
  tags: string[];
}

interface HeaderStat {
  value: string;
  label: string;
}

interface ProcessStepsPropertyPanelProps {
  section: SectionConfig;
  onUpdate: (updates: Partial<SectionConfig>) => void;
}

/* ─── Small reusable input components ─── */
function Field({ label, children }: { label: string; children: React.ReactNode }) {
  return (
    <div>
      <label className="block text-xs font-medium text-gray-600 dark:text-gray-400 mb-1">{label}</label>
      {children}
    </div>
  );
}

const inputCls =
  'w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-md bg-white dark:bg-gray-700 text-gray-900 dark:text-white text-sm';

const textareaCls = inputCls + ' resize-none';

/* ─── Collapsible section wrapper ─── */
function Collapsible({ title, badge, children, defaultOpen = false }: {
  title: string;
  badge?: string;
  children: React.ReactNode;
  defaultOpen?: boolean;
}) {
  const [open, setOpen] = useState(defaultOpen);
  return (
    <div className="border border-gray-200 dark:border-gray-600 rounded-lg overflow-hidden">
      <button
        type="button"
        onClick={() => setOpen(o => !o)}
        className="w-full flex items-center justify-between px-3 py-2.5 bg-gray-50 dark:bg-gray-700 hover:bg-gray-100 dark:hover:bg-gray-600 transition-colors text-left"
      >
        <span className="text-sm font-medium text-gray-800 dark:text-white flex items-center gap-2">
          {title}
          {badge && (
            <span className="text-xs bg-blue-100 dark:bg-blue-900/40 text-blue-700 dark:text-blue-300 px-2 py-0.5 rounded-full">
              {badge}
            </span>
          )}
        </span>
        <span className={`text-gray-400 text-xs transition-transform ${open ? 'rotate-90' : ''}`}>▶</span>
      </button>
      {open && <div className="p-3 space-y-3 bg-white dark:bg-gray-800">{children}</div>}
    </div>
  );
}

/* ─── Main Panel ─── */
export function ProcessStepsPropertyPanel({ section, onUpdate }: ProcessStepsPropertyPanelProps) {
  const data = section.data as any;

  const update = (patch: Record<string, any>) => {
    onUpdate({ data: { ...data, ...patch } });
  };

  /* ── Stats helpers ── */
  const stats: HeaderStat[] = data.stats ?? [];

  const updateStat = (idx: number, field: keyof HeaderStat, val: string) => {
    const next = stats.map((s, i) => (i === idx ? { ...s, [field]: val } : s));
    update({ stats: next });
  };

  const addStat = () => update({ stats: [...stats, { value: '', label: '' }] });

  const removeStat = (idx: number) => update({ stats: stats.filter((_: HeaderStat, i: number) => i !== idx) });

  /* ── Steps helpers ── */
  const steps: ProcessStep[] = data.steps ?? [];

  const updateStep = (idx: number, field: keyof ProcessStep, val: any) => {
    const next = steps.map((s, i) => (i === idx ? { ...s, [field]: val } : s));
    update({ steps: next });
  };

  const updateStepTag = (stepIdx: number, tagIdx: number, val: string) => {
    const next = steps.map((s, i) => {
      if (i !== stepIdx) return s;
      const tags = [...s.tags];
      tags[tagIdx] = val;
      return { ...s, tags };
    });
    update({ steps: next });
  };

  const addTag = (stepIdx: number) => {
    const next = steps.map((s, i) =>
      i === stepIdx ? { ...s, tags: [...s.tags, ''] } : s
    );
    update({ steps: next });
  };

  const removeTag = (stepIdx: number, tagIdx: number) => {
    const next = steps.map((s, i) =>
      i === stepIdx ? { ...s, tags: s.tags.filter((_: string, ti: number) => ti !== tagIdx) } : s
    );
    update({ steps: next });
  };

  const addStep = () =>
    update({
      steps: [
        ...steps,
        { eyebrow: 'New Phase', badge: 'Team Name', title: 'Step Title', description: 'Step description.', tags: [] },
      ],
    });

  const removeStep = (idx: number) => update({ steps: steps.filter((_: ProcessStep, i: number) => i !== idx) });

  const moveStep = (idx: number, dir: -1 | 1) => {
    const next = [...steps];
    const target = idx + dir;
    if (target < 0 || target >= next.length) return;
    [next[idx], next[target]] = [next[target], next[idx]];
    update({ steps: next });
  };

  return (
    <div className="space-y-4">

      {/* ── Header ── */}
      <Collapsible title="Section Header" defaultOpen>
        <Field label="Eyebrow Label">
          <input className={inputCls} value={data.eyebrow ?? ''} onChange={e => update({ eyebrow: e.target.value })} />
        </Field>
        <Field label="Title (before highlight)">
          <input className={inputCls} value={data.sectionTitle ?? ''} onChange={e => update({ sectionTitle: e.target.value })} />
        </Field>
        <Field label="Title Highlight (gradient text)">
          <input className={inputCls} value={data.sectionTitleHighlight ?? ''} onChange={e => update({ sectionTitleHighlight: e.target.value })} />
        </Field>
        <Field label="Description">
          <textarea className={textareaCls} rows={3} value={data.description ?? ''} onChange={e => update({ description: e.target.value })} />
        </Field>
      </Collapsible>

      {/* ── Stats ── */}
      <Collapsible title="Header Stats" badge={`${stats.length}`}>
        {stats.map((stat: HeaderStat, i: number) => (
          <div key={i} className="flex gap-2 items-start">
            <div className="flex-1 space-y-1">
              <input
                className={inputCls}
                placeholder="Value (e.g. 100%)"
                value={stat.value}
                onChange={e => updateStat(i, 'value', e.target.value)}
              />
              <input
                className={inputCls}
                placeholder="Label"
                value={stat.label}
                onChange={e => updateStat(i, 'label', e.target.value)}
              />
            </div>
            <button
              type="button"
              onClick={() => removeStat(i)}
              className="mt-1 p-1.5 text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded"
              title="Remove stat"
            >
              ✕
            </button>
          </div>
        ))}
        <button
          type="button"
          onClick={addStat}
          className="w-full py-2 border border-dashed border-gray-300 dark:border-gray-600 rounded-md text-sm text-gray-500 dark:text-gray-400 hover:border-blue-400 hover:text-blue-500 transition-colors"
        >
          + Add Stat
        </button>
      </Collapsible>

      {/* ── Steps ── */}
      <Collapsible title="Timeline Steps" badge={`${steps.length}`} defaultOpen>
        <div className="space-y-3">
          {steps.map((step: ProcessStep, idx: number) => (
            <Collapsible
              key={idx}
              title={`Step ${idx + 1}: ${step.title || '(untitled)'}`}
            >
              {/* Move / Delete controls */}
              <div className="flex gap-1 mb-2">
                <button type="button" onClick={() => moveStep(idx, -1)} disabled={idx === 0}
                  className="px-2 py-1 text-xs bg-gray-100 dark:bg-gray-700 rounded disabled:opacity-30 hover:bg-gray-200 dark:hover:bg-gray-600">
                  ↑ Up
                </button>
                <button type="button" onClick={() => moveStep(idx, 1)} disabled={idx === steps.length - 1}
                  className="px-2 py-1 text-xs bg-gray-100 dark:bg-gray-700 rounded disabled:opacity-30 hover:bg-gray-200 dark:hover:bg-gray-600">
                  ↓ Down
                </button>
                <button type="button" onClick={() => removeStep(idx)}
                  className="ml-auto px-2 py-1 text-xs bg-red-100 dark:bg-red-900/30 text-red-600 dark:text-red-400 rounded hover:bg-red-200 dark:hover:bg-red-900/50">
                  🗑 Remove
                </button>
              </div>

              <Field label="Eyebrow (phase name)">
                <input className={inputCls} value={step.eyebrow} onChange={e => updateStep(idx, 'eyebrow', e.target.value)} />
              </Field>
              <Field label="Badge (team name)">
                <input className={inputCls} value={step.badge} onChange={e => updateStep(idx, 'badge', e.target.value)} />
              </Field>
              <Field label="Title">
                <input className={inputCls} value={step.title} onChange={e => updateStep(idx, 'title', e.target.value)} />
              </Field>
              <Field label="Description">
                <textarea className={textareaCls} rows={3} value={step.description} onChange={e => updateStep(idx, 'description', e.target.value)} />
              </Field>

              {/* Tags */}
              <Field label={`Tags (${step.tags.length})`}>
                <div className="space-y-1.5">
                  {step.tags.map((tag: string, ti: number) => (
                    <div key={ti} className="flex gap-1">
                      <input
                        className={inputCls}
                        value={tag}
                        onChange={e => updateStepTag(idx, ti, e.target.value)}
                        placeholder="Tag text"
                      />
                      <button type="button" onClick={() => removeTag(idx, ti)}
                        className="px-2 text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded text-sm">
                        ✕
                      </button>
                    </div>
                  ))}
                  <button type="button" onClick={() => addTag(idx)}
                    className="w-full py-1.5 border border-dashed border-gray-300 dark:border-gray-600 rounded text-xs text-gray-500 hover:border-blue-400 hover:text-blue-500 transition-colors">
                    + Add Tag
                  </button>
                </div>
              </Field>
            </Collapsible>
          ))}
        </div>

        <button
          type="button"
          onClick={addStep}
          className="w-full py-2.5 border border-dashed border-blue-300 dark:border-blue-700 rounded-md text-sm text-blue-600 dark:text-blue-400 hover:bg-blue-50 dark:hover:bg-blue-900/20 transition-colors font-medium"
        >
          + Add Step
        </button>
      </Collapsible>

      {/* ── Footer CTA ── */}
      <Collapsible title="Footer CTA">
        <Field label="Title">
          <input className={inputCls} value={data.footerTitle ?? ''} onChange={e => update({ footerTitle: e.target.value })} />
        </Field>
        <Field label="Subtitle">
          <input className={inputCls} value={data.footerSubtitle ?? ''} onChange={e => update({ footerSubtitle: e.target.value })} />
        </Field>
        <Field label="Button Text">
          <input className={inputCls} value={data.footerButtonText ?? ''} onChange={e => update({ footerButtonText: e.target.value })} />
        </Field>
        <Field label="Button Link (href)">
          <input className={inputCls} value={data.footerButtonHref ?? ''} onChange={e => update({ footerButtonHref: e.target.value })} />
        </Field>
      </Collapsible>

      {/* ── Colors ── */}
      <Collapsible title="Accent Colors">
        <div className="grid grid-cols-2 gap-3">
          <Field label="Primary Accent">
            <div className="flex gap-2 items-center">
              <input
                type="color"
                value={data.accentColor ?? '#4F7FFF'}
                onChange={e => update({ accentColor: e.target.value })}
                className="w-10 h-9 rounded border border-gray-300 dark:border-gray-600 cursor-pointer p-0.5 bg-white dark:bg-gray-700"
              />
              <input
                className={inputCls}
                value={data.accentColor ?? '#4F7FFF'}
                onChange={e => update({ accentColor: e.target.value })}
                placeholder="#4F7FFF"
              />
            </div>
          </Field>
          <Field label="Secondary Accent">
            <div className="flex gap-2 items-center">
              <input
                type="color"
                value={data.accentColor2 ?? '#7B5CFF'}
                onChange={e => update({ accentColor2: e.target.value })}
                className="w-10 h-9 rounded border border-gray-300 dark:border-gray-600 cursor-pointer p-0.5 bg-white dark:bg-gray-700"
              />
              <input
                className={inputCls}
                value={data.accentColor2 ?? '#7B5CFF'}
                onChange={e => update({ accentColor2: e.target.value })}
                placeholder="#7B5CFF"
              />
            </div>
          </Field>
        </div>
        <p className="text-xs text-gray-500 dark:text-gray-400">
          Used for gradient text, node hover, button, and top card line.
        </p>
      </Collapsible>

    </div>
  );
}
